+        "rule" | "rules" => SessionPinnedEntityKind::Rule,
+        _ => return Err(SessionError::InvalidEntityUrn(trimmed.to_string())),
+    };
+
+    Ok(ParsedEntityUrn {
+        workspace_slug,
+        kind,
+        entity_id,
