+fn validation_outcome_label(outcome: ValidationOutcome) -> String {
+    match outcome {
+        ValidationOutcome::Passed => "passed".to_string(),
+        ValidationOutcome::Failed => "failed".to_string(),
+        ValidationOutcome::Blocked => "blocked".to_string(),
+    }
+}
